+    fn null_comparison_returns_null_in_join() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE nc (id INTEGER PRIMARY KEY, val INTEGER);")
+            .unwrap();
+        conn.execute("INSERT INTO nc VALUES (1, NULL), (2, 5), (3, NULL);")
+            .unwrap();
